package co.edu.elecciones.controller; import co.edu.elecciones.commons.dto.ApiResponse; import co.edu.elecciones.commons.security.JwtService; import co.edu.elecciones.dto.AuthDtos.*; import co.edu.elecciones.repository.UserRepository; import jakarta.validation.Valid; import org.springframework.security.authentication.*; import org.springframework.security.core.Authentication; import org.springframework.security.core.userdetails.UserDetails; import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/v1/auth") public class AuthController { private final AuthenticationManager auth; private final JwtService jwt; private final UserRepository users; public AuthController(AuthenticationManager a,JwtService j,UserRepository u){auth=a;jwt=j;users=u;} @PostMapping("/login") public ApiResponse<LoginResponse> login(@Valid @RequestBody LoginRequest req){ Authentication ok=auth.authenticate(new UsernamePasswordAuthenticationToken(req.email(),req.password())); String token=jwt.generate((UserDetails)ok.getPrincipal()); var u=users.findByEmail(req.email()).orElseThrow(); return ApiResponse.ok("Login exitoso",new LoginResponse(token,"Bearer",u.id,u.name,u.email,u.role)); } @PostMapping("/logout") public ApiResponse<Void> logout(){return ApiResponse.ok("Logout lógico: elimina el token del frontend",null);} }
